 72→func printVersion() {
 73→	fmt.Print(logoString)
 74→	fmt.Printf("Version:\t%s\n", version)
 75→	fmt.Printf("Git hash:\t%s\n", commit)
 76→	fmt.Printf("Build time:\t%s\n", date)
 77→	fmt.Printf("SQL db version:\t%d\n", repository.Version)
 78→	fmt.Printf("Job archive version:\t%d\n", archive.Version)
 79→}
