 81→func initGops() error {
 82→	if !flagGops {
 83→		return nil
 84→	}
 85→
 86→	if err := agent.Listen(agent.Options{}); err != nil {
 87→		return fmt.Errorf("starting gops agent: %w", err)
 88→	}
 89→	return nil
 90→}
 91→
 92→func loadEnvironment() error {
 93→	if err := godotenv.Load(); err != nil {
 94→		return fmt.Errorf("loading .env file: %w", err)
 95→	}
 96→	return nil
 97→}
 98→
 99→func initConfiguration() error {
100→	ccconf.Init(flagConfigFile)
101→
102→	cfg := ccconf.GetPackageConfig("main")
103→	if cfg == nil {
104→		return fmt.Errorf("main configuration must be present")
105→	}
106→
107→	config.Init(cfg)
108→	return nil
109→}
110→
111→func initDatabase() error {
112→	if config.Keys.DbConfig != nil {
113→		cfg := repository.DefaultConfig()
114→		dc := config.Keys.DbConfig
115→		if dc.CacheSizeMB > 0 {
116→			cfg.DbCacheSizeMB = dc.CacheSizeMB
117→		}
118→		if dc.SoftHeapLimitMB > 0 {
119→			cfg.DbSoftHeapLimitMB = dc.SoftHeapLimitMB
120→		}
121→		if dc.MaxOpenConnections > 0 {
122→			cfg.MaxOpenConnections = dc.MaxOpenConnections
123→		}
124→		if dc.MaxIdleConnections > 0 {
125→			cfg.MaxIdleConnections = dc.MaxIdleConnections
126→		}
127→		if dc.ConnectionMaxIdleTimeMins > 0 {
128→			cfg.ConnectionMaxIdleTime = time.Duration(dc.ConnectionMaxIdleTimeMins) * time.Minute
129→		}
130→		if dc.BusyTimeoutMs > 0 {
131→			cfg.BusyTimeoutMs = dc.BusyTimeoutMs
132→		}
133→		repository.SetConfig(cfg)
134→	}
135→	repository.Connect(config.Keys.DB)
136→	return nil
137→}
138→
139→func handleDatabaseCommands() error {
140→	if flagMigrateDB {
141→		err := repository.MigrateDB(config.Keys.DB)
142→		if err != nil {
143→			return fmt.Errorf("migrating database to version %d: %w", repository.Version, err)
144→		}
145→		cclog.Exitf("MigrateDB Success: Migrated SQLite database at '%s' to version %d.\n",
146→			config.Keys.DB, repository.Version)
147→	}
148→
149→	if flagRevertDB {
150→		err := repository.RevertDB(config.Keys.DB)
151→		if err != nil {
152→			return fmt.Errorf("reverting database to version %d: %w", repository.Version-1, err)
153→		}
154→		cclog.Exitf("RevertDB Success: Reverted SQLite database at '%s' to version %d.\n",
155→			config.Keys.DB, repository.Version-1)
156→	}
157→
158→	if flagForceDB {
159→		err := repository.ForceDB(config.Keys.DB)
160→		if err != nil {
161→			return fmt.Errorf("forcing database to version %d: %w", repository.Version, err)
162→		}
163→		cclog.Exitf("ForceDB Success: Forced SQLite database at '%s' to version %d.\n",
164→			config.Keys.DB, repository.Version)
165→	}
166→
167→	return nil
168→}
169→
170→func handleUserCommands() error {
171→	if config.Keys.DisableAuthentication && (flagNewUser != "" || flagDelUser != "") {
172→		return fmt.Errorf("--add-user and --del-user can only be used if authentication is enabled")
173→	}
174→
175→	if !config.Keys.DisableAuthentication {
176→		if cfg := ccconf.GetPackageConfig("auth"); cfg != nil {
177→			auth.Init(&cfg)
178→		} else {
179→			cclog.Warn("Authentication disabled due to missing configuration")
180→			auth.Init(nil)
181→		}
182→
183→		// Check for default security keys
184→		checkDefaultSecurityKeys()
185→
186→		if flagNewUser != "" {
187→			if err := addUser(flagNewUser); err != nil {
188→				return err
189→			}
190→		}
191→
192→		if flagDelUser != "" {
193→			if err := delUser(flagDelUser); err != nil {
194→				return err
195→			}
196→		}
197→
198→		authHandle := auth.GetAuthInstance()
199→
200→		if flagSyncLDAP {
201→			if err := syncLDAP(authHandle); err != nil {
202→				return err
203→			}
204→		}
205→
206→		if flagGenJWT != "" {
207→			if err := generateJWT(authHandle, flagGenJWT); err != nil {
208→				return err
209→			}
210→		}
211→	}
212→
213→	return nil
214→}
215→
216→// checkDefaultSecurityKeys warns if default JWT keys are detected
217→func checkDefaultSecurityKeys() {
218→	// Default JWT public key from init.go
219→	defaultJWTPublic := "REDACTED"
220→
221→	if os.Getenv("JWT_PUBLIC_KEY") == defaultJWTPublic {
222→		cclog.Warn("Using default JWT keys - not recommended for production environments")
223→	}
224→}
225→
226→func addUser(userSpec string) error {
227→	parts := strings.SplitN(userSpec, ":", 3)
228→	if len(parts) != 3 || len(parts[0]) == 0 {
229→		return fmt.Errorf("invalid user format, want: <username>:[admin,support,manager,api,user]:<password>, have: %s", userSpec)
230→	}
231→
232→	ur := repository.GetUserRepository()
233→	if err := ur.AddUser(&schema.User{
234→		Username: parts[0],
235→		Projects: make([]string, 0),
236→		Password: parts[2],
237→		Roles:    strings.Split(parts[1], ","),
238→	}); err != nil {
239→		return fmt.Errorf("adding user '%s' with roles '%s': %w", parts[0], parts[1], err)
240→	}
241→
242→	cclog.Infof("Add User: Added new user '%s' with roles '%s'", parts[0], parts[1])
243→	return nil
244→}
245→
246→func delUser(username string) error {
247→	ur := repository.GetUserRepository()
248→	if err := ur.DelUser(username); err != nil {
249→		return fmt.Errorf("deleting user '%s': %w", username, err)
250→	}
251→	cclog.Infof("Delete User: Deleted user '%s' from DB", username)
252→	return nil
253→}
254→
255→func syncLDAP(authHandle *auth.Authentication) error {
256→	if authHandle.LdapAuth == nil {
257→		return fmt.Errorf("LDAP authentication is not configured")
258→	}
259→
260→	if err := authHandle.LdapAuth.Sync(); err != nil {
261→		return fmt.Errorf("synchronizing LDAP: %w", err)
262→	}
263→
264→	cclog.Print("Sync LDAP: LDAP synchronization successfull.")
265→	return nil
266→}
267→
268→func generateJWT(authHandle *auth.Authentication, username string) error {
269→	ur := repository.GetUserRepository()
270→	user, err := ur.GetUser(username)
271→	if err != nil {
272→		return fmt.Errorf("getting user '%s': %w", username, err)
273→	}
274→
275→	if !user.HasRole(schema.RoleAPI) {
276→		cclog.Warnf("JWT: User '%s' does not have the role 'api'. REST API endpoints will return error!\n", user.Username)
277→	}
278→
279→	jwt, err := authHandle.JwtAuth.ProvideJWT(user)
280→	if err != nil {
281→		return fmt.Errorf("generating JWT for user '%s': %w", user.Username, err)
282→	}
283→
284→	cclog.Printf("JWT: Successfully generated JWT for user '%s': %s\n", user.Username, jwt)
285→	return nil
286→}
