339→func runServer(ctx context.Context) error {
340→	var wg sync.WaitGroup
341→
342→	// Initialize metric store if configuration is provided
343→	haveMetricstore := false
344→	mscfg := ccconf.GetPackageConfig("metric-store")
345→	if mscfg != nil {
346→		metrics := metricstore.BuildMetricList()
347→		metricstore.Init(mscfg, metrics, &wg)
348→
349→		// Inject repository as NodeProvider to break import cycle
350→		ms := metricstore.GetMemoryStore()
351→		jobRepo := repository.GetJobRepository()
352→		ms.SetNodeProvider(jobRepo)
353→		metricstore.MetricStoreHandle = &metricstore.InternalMetricStore{}
354→		haveMetricstore = true
355→	} else {
356→		metricstore.MetricStoreHandle = nil
357→		cclog.Debug("missing internal metricstore configuration")
358→	}
359→
360→	// Initialize external metric stores if configuration is provided
361→	mscfg = ccconf.GetPackageConfig("metric-store-external")
362→	if mscfg != nil {
363→		err := metricdispatch.Init(mscfg)
364→
365→		if err != nil {
366→			cclog.Debugf("error while initializing external metricdispatch: %v", err)
367→		} else {
368→			haveMetricstore = true
369→		}
370→	}
371→
372→	if !haveMetricstore {
373→		return fmt.Errorf("missing metricstore configuration")
374→	}
375→
376→	// Start archiver and task manager
377→	archiver.Start(repository.GetJobRepository(), ctx)
378→	taskmanager.Start(ccconf.GetPackageConfig("cron"), ccconf.GetPackageConfig("archive"))
379→
380→	// Initialize web UI
381→	cfg := ccconf.GetPackageConfig("ui")
382→	if err := web.Init(cfg); err != nil {
383→		return fmt.Errorf("initializing web UI: %w", err)
384→	}
385→
386→	// Initialize HTTP server
387→	srv, err := NewServer(version, commit, date)
388→	if err != nil {
389→		return fmt.Errorf("creating server: %w", err)
390→	}
391→
392→	// Channel to collect errors from server
393→	errChan := make(chan error, 1)
394→
395→	// Start HTTP server
396→	wg.Go(func() {
397→		if err := srv.Start(ctx); err != nil {
398→			errChan <- err
399→		}
400→	})
401→
402→	// Handle shutdown signals
403→	wg.Add(1)
404→	sigs := make(chan os.Signal, 1)
405→	signal.Notify(sigs, syscall.SIGINT, syscall.SIGTERM)
406→	go func() {
407→		defer wg.Done()
408→		select {
409→		case <-sigs:
410→			cclog.Info("Shutdown signal received")
411→		case <-ctx.Done():
412→		}
413→
414→		runtime.SystemdNotify(false, "Shutting down ...")
415→		srv.Shutdown(ctx)
416→		util.FsWatcherShutdown()
417→		taskmanager.Shutdown()
418→	}()
419→
420→	// Set GC percent if not configured
421→	if os.Getenv(envGOGC) == "" {
422→		// trigger GC when heap grows 15% above the previous live set
423→		debug.SetGCPercent(15)
424→	}
425→	runtime.SystemdNotify(true, "running")
426→
427→	waitDone := make(chan struct{})
428→	go func() {
429→		wg.Wait()
430→		close(waitDone)
431→	}()
432→
433→	go func() {
434→		<-waitDone
435→		close(errChan)
436→	}()
437→
438→	// Wait for either:
439→	// 1. An error from server startup
440→	// 2. Completion of all goroutines (normal shutdown or crash)
441→	select {
442→	case err := <-errChan:
443→		// errChan will be closed when waitDone is closed, which happens
444→		// when all goroutines complete (either from normal shutdown or error)
445→		if err != nil {
446→			return err
447→		}
448→	case <-time.After(100 * time.Millisecond):
449→		// Give the server 100ms to start and report any immediate startup errors
450→		// After that, just wait for normal shutdown completion
451→		select {
452→		case err := <-errChan:
453→			if err != nil {
454→				return err
455→			}
456→		case <-waitDone:
457→			// Normal shutdown completed
458→		}
459→	}
460→
461→	cclog.Print("Graceful shutdown completed!")
462→	return nil
463→}
464→
465→func run() error {
466→	cliInit()
467→
468→	if flagVersion {
469→		printVersion()
470→		return nil
471→	}
472→
473→	// Initialize logger
474→	cclog.Init(flagLogLevel, flagLogDateTime)
475→
476→	// Handle init flag
477→	if flagInit {
478→		initEnv()
479→		cclog.Exit("Successfully setup environment!\n" +
480→			"Please review config.json and .env and adjust it to your needs.\n" +
481→			"Add your job-archive at ./var/job-archive.")
482→	}
483→
484→	// Initialize gops agent
485→	if err := initGops(); err != nil {
486→		return err
487→	}
488→
489→	// Initialize subsystems in dependency order:
490→	// 1. Load environment variables from .env file (contains sensitive configuration)
491→	// 2. Load configuration from config.json (may reference environment variables)
492→	// 3. Handle database migration commands if requested
493→	// 4. Initialize database connection (requires config for connection string)
494→	// 5. Handle user commands if requested (requires database and authentication config)
495→	// 6. Initialize subsystems like archive and metrics (require config and database)
496→
497→	// Load environment and configuration
498→	if err := loadEnvironment(); err != nil {
499→		return err
500→	}
501→
502→	if err := initConfiguration(); err != nil {
503→		return err
504→	}
505→
506→	// Handle database migration (migrate, revert, force)
507→	if err := handleDatabaseCommands(); err != nil {
508→		return err
509→	}
510→
511→	// Initialize database
512→	if err := initDatabase(); err != nil {
513→		return err
514→	}
515→
516→	// Optimize database if requested
517→	if flagOptimizeDB {
518→		db := repository.GetConnection()
519→		cclog.Print("Running VACUUM to reclaim space and defragment database...")
520→		if _, err := db.DB.Exec("VACUUM"); err != nil {
521→			return fmt.Errorf("VACUUM failed: %w", err)
522→		}
523→		cclog.Print("Running ANALYZE to update query planner statistics...")
524→		if _, err := db.DB.Exec("ANALYZE"); err != nil {
525→			return fmt.Errorf("ANALYZE failed: %w", err)
526→		}
527→		cclog.Exitf("OptimizeDB Success: Database '%s' optimized (VACUUM + ANALYZE).\n", config.Keys.DB)
528→	}
529→
530→	// Handle user commands (add, delete, sync, JWT)
531→	if err := handleUserCommands(); err != nil {
532→		return err
533→	}
534→
535→	// Initialize subsystems (archive, metrics, taggers)
536→	if err := initSubsystems(); err != nil {
537→		return err
538→	}
539→
540→	// Handle checkpoint cleanup
541→	if flagCleanupCheckpoints {
542→		mscfg := ccconf.GetPackageConfig("metric-store")
543→		if mscfg == nil {
544→			return fmt.Errorf("metric-store configuration required for checkpoint cleanup")
545→		}
546→		if err := json.Unmarshal(mscfg, &metricstore.Keys); err != nil {
547→			return fmt.Errorf("decoding metric-store config: %w", err)
548→		}
549→		if metricstore.Keys.NumWorkers <= 0 {
550→			metricstore.Keys.NumWorkers = min(goruntime.NumCPU()/2+1, metricstore.DefaultMaxWorkers)
551→		}
552→
553→		d, err := time.ParseDuration(metricstore.Keys.RetentionInMemory)
554→		if err != nil {
555→			return fmt.Errorf("parsing retention-in-memory: %w", err)
556→		}
557→		from := time.Now().Add(-d)
558→		deleteMode := metricstore.Keys.Cleanup == nil || metricstore.Keys.Cleanup.Mode != "archive"
559→		cleanupDir := ""
560→		if !deleteMode {
561→			cleanupDir = metricstore.Keys.Cleanup.RootDir
562→		}
563→
564→		cclog.Infof("Cleaning up checkpoints older than %s...", from.Format(time.RFC3339))
565→		n, err := metricstore.CleanupCheckpoints(
566→			metricstore.Keys.Checkpoints.RootDir, cleanupDir, from.Unix(), deleteMode)
567→		if err != nil {
568→			return fmt.Errorf("checkpoint cleanup: %w", err)
569→		}
570→		if deleteMode {
571→			cclog.Exitf("Cleanup done: %d checkpoint files deleted.", n)
572→		} else {
573→			cclog.Exitf("Cleanup done: %d checkpoint files archived to parquet.", n)
574→		}
575→	}
576→
577→	// Exit if start server is not requested
578→	if !flagServer {
579→		cclog.Exit("No errors, server flag not set. Exiting cc-backend.")
580→	}
581→
582→	// Run server with context
583→	ctx, cancel := context.WithCancel(context.Background())
584→	defer cancel()
585→
586→	return runServer(ctx)
587→}
588→
589→func main() {
590→	if err := run(); err != nil {
591→		cclog.Error(err.Error())
592→		os.Exit(1)
593→	}
594→}
