224→// handleStartJob processes job start messages received via NATS.
225→// The payload parameter contains JSON following the schema.Job structure.
226→// Jobs are validated, checked for duplicates, and inserted into the database.
227→func (api *NatsAPI) handleStartJob(payload string) {
228→	if payload == "" {
229→		cclog.Error("NATS start job: payload is empty")
230→		return
231→	}
232→	req := schema.Job{
233→		Shared:           "none",
234→		MonitoringStatus: schema.MonitoringStatusRunningOrArchiving,
235→	}
236→
237→	dec := json.NewDecoder(strings.NewReader(payload))
238→	dec.DisallowUnknownFields()
239→	if err := dec.Decode(&req); err != nil {
240→		cclog.Errorf("NATS start job: parsing request failed: %v", err)
241→		return
242→	}
243→
244→	cclog.Debugf("NATS start job: %s", req.GoString())
245→	req.State = schema.JobStateRunning
246→
247→	if err := importer.SanityChecks(&req); err != nil {
248→		cclog.Errorf("NATS start job: sanity check failed: %v", err)
249→		return
250→	}
251→
252→	var unlockOnce sync.Once
253→	api.RepositoryMutex.Lock()
254→	defer unlockOnce.Do(api.RepositoryMutex.Unlock)
255→
256→	jobs, err := api.JobRepository.FindAll(&req.JobID, &req.Cluster, nil)
257→	if err != nil && err != sql.ErrNoRows {
258→		cclog.Errorf("NATS start job: checking for duplicate failed: %v", err)
259→		return
260→	}
261→	if err == nil {
262→		for _, job := range jobs {
263→			if (req.StartTime - job.StartTime) < secondsPerDay {
264→				cclog.Errorf("NATS start job: job with jobId %d, cluster %s already exists (dbid: %d)",
265→					req.JobID, req.Cluster, job.ID)
266→				return
267→			}
268→		}
269→	}
270→
271→	// When tags are present, insert directly into the job table so that the
272→	// returned ID can be used with AddTagOrCreate (which queries the job table).
273→	var id int64
274→	if len(req.Tags) > 0 {
275→		id, err = api.JobRepository.StartDirect(&req)
276→	} else {
277→		id, err = api.JobRepository.Start(&req)
278→	}
279→	if err != nil {
280→		cclog.Errorf("NATS start job: insert into database failed: %v", err)
281→		return
282→	}
283→	unlockOnce.Do(api.RepositoryMutex.Unlock)
284→
285→	for _, tag := range req.Tags {
286→		if _, err := api.JobRepository.AddTagOrCreate(nil, id, tag.Type, tag.Name, tag.Scope); err != nil {
287→			cclog.Errorf("NATS start job: adding tag to new job %d failed: %v", id, err)
288→			return
289→		}
290→	}
291→
292→	cclog.Infof("NATS: new job (id: %d): cluster=%s, jobId=%d, user=%s, startTime=%d",
293→		id, req.Cluster, req.JobID, req.User, req.StartTime)
294→}
295→
296→// handleStopJob processes job stop messages received via NATS.
297→// The payload parameter contains JSON following the StopJobAPIRequest structure.
298→// The job is marked as stopped in the database and archiving is triggered if monitoring is enabled.
299→func (api *NatsAPI) handleStopJob(payload string) {
300→	if payload == "" {
301→		cclog.Error("NATS stop job: payload is empty")
302→		return
303→	}
304→	var req StopJobAPIRequest
305→
306→	dec := json.NewDecoder(strings.NewReader(payload))
307→	dec.DisallowUnknownFields()
308→	if err := dec.Decode(&req); err != nil {
309→		cclog.Errorf("NATS job stop: parsing request failed: %v", err)
310→		return
311→	}
312→
313→	if req.JobID == nil {
314→		cclog.Errorf("NATS job stop: the field 'jobId' is required")
315→		return
316→	}
317→
318→	isCached := false
319→	job, err := api.JobRepository.FindCached(req.JobID, req.Cluster, req.StartTime)
320→	if err != nil {
321→		// Not in cache, try main job table
322→		job, err = api.JobRepository.Find(req.JobID, req.Cluster, req.StartTime)
323→		if err != nil {
324→			cclog.Errorf("NATS job stop: finding job failed: %v", err)
325→			return
326→		}
327→	} else {
328→		isCached = true
329→	}
330→
331→	if job.State != schema.JobStateRunning {
332→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: job has already been stopped (state is: %s)",
333→			job.JobID, job.ID, job.Cluster, job.State)
334→		return
335→	}
336→
337→	if job.StartTime > req.StopTime {
338→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: stopTime %d must be >= startTime %d",
339→			job.JobID, job.ID, job.Cluster, req.StopTime, job.StartTime)
340→		return
341→	}
342→
343→	if req.State != "" && !req.State.Valid() {
344→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: invalid job state: %#v",
345→			job.JobID, job.ID, job.Cluster, req.State)
346→		return
347→	} else if req.State == "" {
348→		req.State = schema.JobStateCompleted
349→	}
350→
351→	job.Duration = int32(req.StopTime - job.StartTime)
352→	job.State = req.State
353→	api.JobRepository.Mutex.Lock()
354→	defer api.JobRepository.Mutex.Unlock()
355→
356→	// If the job is still in job_cache, transfer it to the job table first
357→	if isCached {
358→		newID, err := api.JobRepository.TransferCachedJobToMain(*job.ID)
359→		if err != nil {
360→			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: transferring cached job failed: %v",
361→				job.JobID, *job.ID, job.Cluster, err)
362→			return
363→		}
364→		cclog.Infof("NATS: transferred cached job to main table: old id %d -> new id %d (jobId=%d)", *job.ID, newID, job.JobID)
365→		job.ID = &newID
366→	}
367→
368→	if err := api.JobRepository.Stop(*job.ID, job.Duration, job.State, job.MonitoringStatus); err != nil {
369→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: marking job as '%s' failed: %v",
370→			job.JobID, *job.ID, job.Cluster, job.State, err)
371→		return
372→	}
373→
374→	cclog.Infof("NATS: archiving job (dbid: %d): cluster=%s, jobId=%d, user=%s, startTime=%d, duration=%d, state=%s",
375→		*job.ID, job.Cluster, job.JobID, job.User, job.StartTime, job.Duration, job.State)
376→
377→	if job.MonitoringStatus == schema.MonitoringStatusDisabled {
378→		return
379→	}
380→
381→	archiver.TriggerArchiving(job)
382→}
